// generar_215_rangos_unidades_orina_tiroides.js
// CHIQUI Entre Señales — Rangos y unidades completos (orina + tiroides)
//
// Complementa el generar_214 con lo que faltó del spec:
// - TSH Canina con rango por defecto 0.05-0.42 ng/mL (editable si el
//   laboratorio usa otro intervalo).
// - Unidades por defecto en tiroides: T4 Total µg/dL, T4 Libre ng/dL,
//   TSH Canina/Felina ng/mL, T3 Total ng/dL (antes quedaban vacías).
// - Guías en sedimento: Eritrocitos y Leucocitos indican "cantidad por
//   campo, ej. 0-2"; Olor y Otros hallazgos también con ejemplo.
//
// Ya estaban desde el 214 (verificado): USG perro 1.015-1.045 / gato
// 1.035-1.060, pH perro 5.5-7.5 / gato 6.0-7.5, T4 Total perro 1.0-4.0
// / gato 0.8-4.7 µg/dL.
//
// NOTA: si una mascota ya tiene un examen anterior del mismo tipo, los
// rangos GUARDADOS en ese examen tienen prioridad sobre los "por
// defecto" (diseño intencional: se recuerda el rango del laboratorio
// real). Los rangos por defecto aplican al primer examen de cada tipo.
//
// Solo reescribe components/ExamenesLab.tsx. No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_215_rangos_unidades_orina_tiroides.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'components/ExamenesLab.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo escrito correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
